using System;
using System.Collections;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.SceneManagement;
using UnityEngine.UI;

/// <summary>
/// Menu Principal (Tarefa #22) — primeira tela do jogo, com "Continuar",
/// "Novo Jogo", "New Game+", "Carregar", "Opções", "Galeria", "Créditos" e "Sair".
///
/// - <b>Continuar</b>: carrega o autoguardar directamente (sem escolher
///   slot). O botão fica desactivado (não interactivo) se
///   <see cref="SaveManager.HasAutoSave"/> for false.
/// - <b>Novo Jogo</b>: repõe <see cref="PlayerProgress"/>,
///   <see cref="WorldState"/> e <see cref="GameVariables"/> para os valores
///   configurados no Inspector no arranque (ResetForNewGame — ver
///   PlayerProgress.cs) e carrega <see cref="newGameSceneName"/>. Se já
///   existir um autoguardar, pede confirmação antes (o ficheiro de save NÃO é
///   apagado — apenas o estado em memória é reiniciado).
/// - <b>New Game+</b> (Tarefa #33): visível apenas quando
///   <see cref="PlayerProgress.IsPostGameRewardActive"/> é true. Preserva
///   animais libertados, upgrades e variáveis de emblemas (Gaia/Apolo/Zeus)
///   e reinicia o resto — ver <see cref="PlayerProgress.StartNewGamePlus"/>.
/// - <b>Carregar</b>: abre <see cref="saveMenu"/> em modo Carregar (escolher
///   entre autoguardar e slots manuais — mesmo painel usado no Menu de
///   Pausa).
/// - <b>Opções</b>: abre <see cref="optionsPanel"/> (versão simplificada das
///   Opções, sem Salvar/Carregar/Regressar).
/// - <b>Galeria</b>: abre <see cref="galeriaPanel"/> — grelha de ilustrações/
///   artes conceptuais desbloqueadas (Tarefa #39).
/// - <b>Créditos</b>: abre <see cref="creditosPanel"/> — scroll de créditos
///   (Tarefa #39).
/// - <b>Sair</b>: fecha a aplicação, com confirmação.
///
/// Montagem no Editor:
/// - Ligar os 8 botões principais e "mainButtonsRoot" (GameObject com os botões,
///   escondido enquanto qualquer sub-painel está aberto).
/// - "newGameButton": sempre visível. "newGamePlusButton": só interactivo pós-game.
/// - "newGameSceneName": nome da cena inicial de uma nova partida.
/// - "saveMenu": SaveMenuController (modo Carregar).
/// - "optionsPanel": MainMenuOptionsUI.
/// - "galeriaPanel": GaleriaUI.
/// - "creditosPanel": CreditosUI.
/// - "confirmPanel"/"confirmText"/"confirmYesButton"/"confirmNoButton":
///   diálogo de confirmação genérico, reaproveitado para "Novo Jogo", "NG+" e "Sair".
/// </summary>
public class MainMenuController : MonoBehaviour
{
    [Header("Botões Principais")]
    [SerializeField] private Button continueButton;
    [SerializeField] private Button newGameButton;
    [Tooltip("Botão New Game+ (Tarefa #33) — mostrado sempre, mas só interactivo quando IsPostGameRewardActive é true.")]
    [SerializeField] private Button newGamePlusButton;
    [SerializeField] private Button loadButton;
    [SerializeField] private Button optionsButton;
    [SerializeField] private Button galeriaButton;
    [SerializeField] private Button creditosButton;
    [SerializeField] private Button quitButton;
    [SerializeField] private GameObject mainButtonsRoot;

    [Tooltip("Primeiro botão a seleccionar ao abrir o menu (e ao voltar de um sub-painel).")]
    [SerializeField] private Selectable firstSelectable;

    [Header("Novo Jogo")]
    [Tooltip("Nome da cena carregada ao escolher 'Novo Jogo' (primeira área jogável).")]
    [SerializeField] private string newGameSceneName;

    [Header("Sub-Painéis")]
    [SerializeField] private SaveMenuController saveMenu;
    [SerializeField] private MainMenuOptionsUI optionsPanel;
    [SerializeField] private GaleriaUI galeriaPanel;
    [SerializeField] private CreditosUI creditosPanel;

    [Header("Confirmação")]
    [SerializeField] private GameObject confirmPanel;
    [SerializeField] private TMP_Text confirmText;
    [SerializeField] private Button confirmYesButton;
    [SerializeField] private Button confirmNoButton;
    [SerializeField] private string newGameWithSaveConfirmText =
        "Começar um Novo Jogo? O teu progresso guardado não será apagado, mas o jogo actual vai recomeçar do início.";
    [SerializeField] private string newGamePlusConfirmText =
        "Iniciar New Game+? Os teus animais, upgrades e emblemas serão preservados, mas o resto do progresso vai recomeçar.";
    [SerializeField] private string quitConfirmText = "Sair do jogo?";

    private Action _pendingConfirmAction;

    private void Awake()
    {
        if (continueButton != null) continueButton.onClick.AddListener(OnContinue);
        if (newGameButton != null) newGameButton.onClick.AddListener(OnNewGame);
        if (newGamePlusButton != null) newGamePlusButton.onClick.AddListener(OnNewGamePlus);
        if (loadButton != null) loadButton.onClick.AddListener(OnLoad);
        if (optionsButton != null) optionsButton.onClick.AddListener(OnOptions);
        if (galeriaButton != null) galeriaButton.onClick.AddListener(OnGaleria);
        if (creditosButton != null) creditosButton.onClick.AddListener(OnCreditos);
        if (quitButton != null) quitButton.onClick.AddListener(OnQuit);

        if (confirmYesButton != null) confirmYesButton.onClick.AddListener(OnConfirmYes);
        if (confirmNoButton != null) confirmNoButton.onClick.AddListener(OnConfirmNo);
        if (confirmPanel != null) confirmPanel.SetActive(false);

        if (saveMenu != null) saveMenu.Closed += OnSubPanelClosed;
        if (optionsPanel != null) optionsPanel.Closed += OnSubPanelClosed;
        if (galeriaPanel != null) galeriaPanel.Closed += OnSubPanelClosed;
        if (creditosPanel != null) creditosPanel.Closed += OnSubPanelClosed;
    }

    private void OnEnable()
    {
        Refresh();
    }

    private void Refresh()
    {
        bool hasAuto = SaveManager.Instance != null && SaveManager.Instance.HasAutoSave();
        if (continueButton != null) continueButton.interactable = hasAuto;

        // Tarefa #33: NG+ só interactivo após pós-game.
        // Bug #4: antes de o save ser carregado, PlayerProgress pode estar no estado
        // inicial (IsPostGameRewardActive = false), mesmo que o autosave seja pós-game.
        // Solução: se a instância ainda não tem a recompensa, consultar o autosave.
        bool isPostGame = PlayerProgress.Instance?.IsPostGameRewardActive ?? false;
        if (!isPostGame && SaveManager.Instance != null)
        {
            var peek = SaveManager.Instance.PeekSlot(-1, true); // lê metadados sem aplicar
            if (peek?.enabledUpgradeIds != null
                && peek.enabledUpgradeIds.Contains(PlayerProgress.RecompensaPosJogoUpgradeId))
                isPostGame = true;
        }
        if (newGamePlusButton != null) newGamePlusButton.interactable = isPostGame;

        ShowMainButtons();
        SelectFirst();
    }

    // ==================== Continuar ====================

    private void OnContinue()
    {
        var manager = SaveManager.Instance;
        if (manager == null || !manager.HasAutoSave()) return;

        var data = manager.PeekSlot(-1, true);
        if (data == null) return;

        StartCoroutine(LoadAutosaveRoutine(data));
    }

    private IEnumerator LoadAutosaveRoutine(SaveData data)
    {
        // Tarefa #16 (tela de loading): troca de cena via LoadingScreenController
        // — o save só é aplicado depois da nova cena activar, com o overlay
        // ainda visível (mesmo padrão de SaveMenuController.LoadRoutine).
        if (!string.IsNullOrEmpty(data.sceneName) && SceneManager.GetActiveScene().name != data.sceneName)
        {
            bool done = false;
            LoadingScreenController.Instance.LoadScene(data.sceneName, () =>
            {
                SaveManager.Instance?.LoadAutosave();
                done = true;
            });

            while (!done) yield return null;
        }
        else
        {
            SaveManager.Instance?.LoadAutosave();
        }
    }

    // ==================== Novo Jogo ====================

    private void OnNewGame()
    {
        bool hasAuto = SaveManager.Instance != null && SaveManager.Instance.HasAutoSave();

        if (hasAuto)
            RequestConfirm(newGameWithSaveConfirmText, StartNewGame);
        else
            StartNewGame();
    }

    private void StartNewGame()
    {
        // Tarefa #22 — repõe os singletons persistentes para os valores de
        // arranque sem os destruir (ver PlayerProgress.ResetForNewGame).
        PlayerProgress.Instance?.ResetForNewGame();
        WorldState.Instance?.ResetForNewGame();
        GameVariables.Instance?.ResetForNewGame();

        if (string.IsNullOrEmpty(newGameSceneName))
        {
            Debug.LogWarning("[MainMenuController] 'newGameSceneName' não está configurado — não é possível iniciar um Novo Jogo.");
            return;
        }

        LoadingScreenController.Instance.LoadScene(newGameSceneName);
    }

    // ==================== New Game+ (Tarefa #33) ====================

    private void OnNewGamePlus()
    {
        RequestConfirm(newGamePlusConfirmText, StartNewGamePlus);
    }

    private void StartNewGamePlus()
    {
        // Task 1.1: ao iniciar pelo menu principal, PlayerProgress está nos valores
        // iniciais (listas vazias). Usar o autosave como fonte para preservar
        // animais/upgrades/emblemas correctamente, independentemente do estado em memória.
        var save = SaveManager.Instance?.PeekSlot(-1, true);
        if (save != null)
            PlayerProgress.Instance?.StartNewGamePlusFromSave(save);
        else
            PlayerProgress.Instance?.StartNewGamePlus(); // fallback (save não existe)

        WorldState.Instance?.ResetForNewGame();
        // GameVariables já é reposto e restaurado internamente pelo StartNewGamePlusFromSave.

        if (string.IsNullOrEmpty(newGameSceneName))
        {
            Debug.LogWarning("[MainMenuController] 'newGameSceneName' não está configurado — não é possível iniciar NG+.");
            return;
        }

        LoadingScreenController.Instance.LoadScene(newGameSceneName);
    }

    // ==================== Carregar ====================

    private void OnLoad()
    {
        if (saveMenu == null) return;

        HideMainButtons();
        saveMenu.OpenForLoad();
    }

    // ==================== Opções ====================

    private void OnOptions()
    {
        if (optionsPanel == null) return;

        HideMainButtons();
        optionsPanel.Open();
    }

    // ==================== Galeria ====================

    private void OnGaleria()
    {
        if (galeriaPanel == null) return;

        HideMainButtons();
        galeriaPanel.Open();
    }

    // ==================== Créditos ====================

    private void OnCreditos()
    {
        if (creditosPanel == null) return;

        HideMainButtons();
        creditosPanel.Open();
    }

    // ==================== Sair ====================

    private void OnQuit()
    {
        RequestConfirm(quitConfirmText, QuitApplication);
    }

    private static void QuitApplication()
    {
#if UNITY_EDITOR
        UnityEditor.EditorApplication.isPlaying = false;
#else
        Application.Quit();
#endif
    }

    // ==================== Sub-Painéis ====================

    private void OnSubPanelClosed()
    {
        ShowMainButtons();
        SelectFirst();
    }

    private void ShowMainButtons()
    {
        if (mainButtonsRoot != null) mainButtonsRoot.SetActive(true);
    }

    private void HideMainButtons()
    {
        if (mainButtonsRoot != null) mainButtonsRoot.SetActive(false);
    }

    private void SelectFirst()
    {
        if (EventSystem.current != null && firstSelectable != null)
            EventSystem.current.SetSelectedGameObject(firstSelectable.gameObject);
    }

    // ==================== Confirmação ====================

    private void RequestConfirm(string message, Action onYes)
    {
        if (confirmPanel == null)
        {
            // Sem painel de confirmação configurado: executa directamente.
            onYes?.Invoke();
            return;
        }

        _pendingConfirmAction = onYes;
        if (confirmText != null) confirmText.text = message;
        confirmPanel.SetActive(true);

        if (EventSystem.current != null && confirmYesButton != null)
            EventSystem.current.SetSelectedGameObject(confirmYesButton.gameObject);
    }

    private void OnConfirmYes()
    {
        var action = _pendingConfirmAction;
        HideConfirm();
        action?.Invoke();
    }

    private void OnConfirmNo() => HideConfirm();

    private void HideConfirm()
    {
        _pendingConfirmAction = null;
        if (confirmPanel != null) confirmPanel.SetActive(false);
        SelectFirst();
    }
}
